#![expect(clippy::unwrap_used)] // build tool, so okay here

/// Docs read from `/docs`
mod docs;

/// Examples read from `/examples`
mod examples;

/// Python API reference generated by mkdocs
mod python;

/// C++ API reference generated by Doxygen
mod cpp;

use std::borrow::Cow;
use std::cell::{Cell, RefCell};
use std::io::IsTerminal as _;
use std::time::Duration;

use camino::Utf8Path;
use cargo_metadata::Package;
use cargo_metadata::semver::Version;
use indicatif::{MultiProgress, ProgressBar};

pub fn run(release_version: Option<Version>) -> anyhow::Result<Vec<Document>> {
    let ctx = Context::new(release_version)?;
    docs::ingest(&ctx)?;
    examples::ingest(&ctx)?;
    python::ingest(&ctx)?;
    cpp::ingest(&ctx)?;
    Ok(ctx.finish())
}

struct Context {
    progress: MultiProgress,
    metadata: cargo_metadata::Metadata,
    id_gen: IdGen,
    documents: RefCell<Vec<Document>>,
    release_version: Option<Version>,
    is_tty: bool,
}

impl Context {
    fn new(release_version: Option<Version>) -> anyhow::Result<Self> {
        Ok(Self {
            progress: MultiProgress::new(),
            metadata: re_build_tools::cargo_metadata()?,
            id_gen: IdGen::new(),
            documents: RefCell::new(Vec::new()),
            release_version,
            is_tty: std::io::stdout().is_terminal(),
        })
    }

    fn is_tty(&self) -> bool {
        self.is_tty
    }

    fn progress_bar(&self, prefix: impl Into<Cow<'static, str>>) -> ProgressBar {
        let bar = ProgressBar::new_spinner().with_prefix(prefix);
        bar.enable_steady_tick(Duration::from_millis(100));
        #[expect(clippy::literal_string_with_formatting_args)]
        bar.set_style(bar.style().template("{spinner} {prefix}: {msg}").unwrap());
        self.progress.add(bar)
    }

    #[expect(clippy::needless_pass_by_value)]
    fn finish_progress_bar(&self, bar: ProgressBar) {
        bar.disable_steady_tick();
        bar.finish_and_clear();
        self.progress.remove(&bar);
        let _ = bar;
    }

    fn workspace_root(&self) -> &Utf8Path {
        &self.metadata.workspace_root
    }

    fn rerun_pkg(&self) -> &Package {
        self.metadata
            .packages
            .iter()
            .find(|pkg| pkg.name.as_str() == "rerun")
            .unwrap()
    }

    fn release_version(&self) -> &Version {
        self.release_version
            .as_ref()
            .unwrap_or_else(|| &self.rerun_pkg().version)
    }

    fn push(&self, data: DocumentData) {
        self.documents.borrow_mut().push(Document {
            id: self.id_gen.next(),
            weight: data.kind.weight(),
            data,
        });
    }

    fn finish(self) -> Vec<Document> {
        let documents = self.documents.into_inner();
        println!("collected {} documents", documents.len());
        documents
    }
}

#[derive(serde::Serialize, serde::Deserialize)]
pub struct Document {
    id: u64,
    /// Page-type ranking weight, used by the `weight:desc` ranking rule
    /// so that guides and examples rank above individual API symbols.
    #[serde(default)]
    weight: u64,
    #[serde(flatten)]
    data: DocumentData,
}

impl Document {
    pub const PRIMARY_KEY: &'static str = "id";

    pub fn title(&self) -> &String {
        &self.data.title
    }

    pub fn url(&self) -> &String {
        &self.data.url
    }

    pub fn content(&self) -> &String {
        &self.data.content
    }
}

#[derive(Debug, serde::Serialize, serde::Deserialize)]
struct DocumentData {
    kind: DocumentKind,
    title: String,
    hidden_tags: Vec<String>,
    tags: Vec<String>,
    content: String,
    url: String,
    /// Thumbnail shown next to the result in the website's search dialog.
    #[serde(skip_serializing_if = "Option::is_none", default)]
    image: Option<String>,
}

#[derive(Clone, Copy, Debug, serde::Serialize, serde::Deserialize)]
#[serde(rename_all = "snake_case")]
enum DocumentKind {
    Docs,
    Examples,
    Python,
    Cpp,
}

impl DocumentKind {
    /// Documents are ranked by this weight (descending) after word/typo/proximity/attribute
    /// matching, so that whole-page guides beat the thousands of per-symbol API documents
    /// for generic queries, while exact symbol matches still win on `exactness`.
    fn weight(self) -> u64 {
        match self {
            Self::Docs => 10,
            Self::Examples => 8,
            Self::Python | Self::Cpp => 3,
        }
    }
}

/// Remove HTML tags (e.g. the `<picture>`/`<img>` embeds in docs and example
/// READMEs) so attribute soup like `srcset="…1024w.png"` neither pollutes
/// search matching nor leaks into result excerpts on the website.
pub fn strip_html_tags(s: &str) -> String {
    let mut out = String::with_capacity(s.len());
    let mut in_tag = false;
    for c in s.chars() {
        match c {
            '<' => {
                in_tag = true;
                // Tags act as word boundaries.
                out.push(' ');
            }
            '>' if in_tag => in_tag = false,
            c if !in_tag => out.push(c),
            _ => {}
        }
    }
    out
}

struct IdGen {
    v: Cell<u64>,
}

impl IdGen {
    fn new() -> Self {
        Self { v: Cell::new(0) }
    }

    fn next(&self) -> u64 {
        self.v.replace(self.v.get() + 1)
    }
}
